                    return False

                if member.issym() or member.islnk():
                    link = member.linkname
                    if os.path.isabs(link):
                        if not _inside_dest(os.path.join(dest_real, link)):
                            return False
                    else:
                        link_dir = os.path.dirname(os.path.join(dest_real, member.name))
                        if not _inside_dest(os.path.join(link_dir, link)):
                            return False

                tar.extract(member, path=dest_path)

        return True
    except Exception:
