def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        if not os.path.isfile(tar_path):
            return False

        dest_real = os.path.realpath(dest_path)
        os.makedirs(dest_path, exist_ok=True)

        dest_prefix = dest_real if dest_real.endswith(os.sep) else dest_real + os.sep

        def _inside_dest(path):
            norm = os.path.normpath(path)
            return norm == dest_real or norm.startswith(dest_prefix)

        with tarfile.open(tar_path, 'r:*') as tar:
            for member in tar.getmembers():
                if os.path.isabs(member.name):
                    member_path = os.path.normpath(member.name)
                else:
                    member_path = os.path.normpath(os.path.join(dest_real, member.name))

                if not _inside_dest(member_path):
                    return False

                if member.issym() or member.islnk():
                    link = member.linkname
                    if os.path.isabs(link):
                        link_path = os.path.normpath(link)
                    else:
                        link_dir = os.path.dirname(member_path)
                        link_path = os.path.normpath(os.path.join(link_dir, link))
                    if not _inside_dest(link_path):
                        return False

                tar.extract(member, path=dest_path)

        return True
    except Exception:
        return False

