def _mode_to_str(mode: int) -> str:
    if stat.S_ISDIR(mode):
        file_type = "d"
    elif stat.S_ISLNK(mode):
        file_type = "l"
    elif stat.S_ISCHR(mode):
        file_type = "c"
    elif stat.S_ISBLK(mode):
        file_type = "b"
    elif stat.S_ISSOCK(mode):
        file_type = "s"
    elif stat.S_ISFIFO(mode):
        file_type = "p"
    elif stat.S_ISREG(mode):
        file_type = "-"
    else:
        file_type = "?"

    perms = []

    # Owner
    r = bool(mode & stat.S_IRUSR)
    w = bool(mode & stat.S_IWUSR)
    x = bool(mode & stat.S_IXUSR)
    s = bool(mode & stat.S_ISUID)
    perms.append("r" if r else "-")
    perms.append("w" if w else "-")
    if s and x:
        perms.append("s")
    elif s:
        perms.append("S")
    else:
        perms.append("x" if x else "-")

    # Group
    r = bool(mode & stat.S_IRGRP)
    w = bool(mode & stat.S_IWGRP)
    x = bool(mode & stat.S_IXGRP)
    s = bool(mode & stat.S_ISGID)
    perms.append("r" if r else "-")
    perms.append("w" if w else "-")
    if s and x:
        perms.append("s")
    elif s:
        perms.append("S")
    else:
        perms.append("x" if x else "-")

    # Other
    r = bool(mode & stat.S_IROTH)
    w = bool(mode & stat.S_IWOTH)
    x = bool(mode & stat.S_IXOTH)
    t = bool(mode & stat.S_ISVTX)
    perms.append("r" if r else "-")
    perms.append("w" if w else "-")
    if t and x:
        perms.append("t")
    elif t:
        perms.append("T")
    else:
        perms.append("x" if x else "-")

    return file_type + "".join(perms)


def _format_time(mtime: float) -> str:
    now = time.time()
    six_months = 180 * 24 * 60 * 60
    if abs(now - mtime) > six_months:
        return time.strftime("%b %e  %Y", time.localtime(mtime))
    return time.strftime("%b %e %H:%M", time.localtime(mtime))


def get_ls_result(dir_path: str) -> str:
    try:
        with os.scandir(dir_path) as it:
            entries = sorted(it, key=lambda e: e.name)
    except (OSError, ValueError):
        return ""

    rows = []
    total_blocks = 0
    for entry in entries:
        try:
            st = entry.stat(follow_symlinks=False)
        except OSError:
            continue

        total_blocks += st.st_blocks

        try:
            owner = pwd.getpwuid(st.st_uid).pw_name
        except KeyError:
            owner = str(st.st_uid)

        try:
            group = grp.getgrgid(st.st_gid).gr_name
        except KeyError:
            group = str(st.st_gid)

        name = entry.name
        if stat.S_ISLNK(st.st_mode):
            try:
                target = os.readlink(entry.path)
            except OSError:
                target = "?"
            name = f"{name} -> {target}"

        rows.append(
            (
                _mode_to_str(st.st_mode),
                st.st_nlink,
                owner,
                group,
                st.st_size,
                _format_time(st.st_mtime),
                name,
            )
        )

    if not rows:
        return f"total {total_blocks // 2}"

    w_link = max(len(str(r[1])) for r in rows)
    w_owner = max(len(r[2]) for r in rows)
    w_group = max(len(r[3]) for r in rows)
    w_size = max(len(str(r[4])) for r in rows)

    lines = [f"total {total_blocks // 2}"]
    for mode, nlink, owner, group, size, mtime, name in rows:
        lines.append(
            f"{mode} {nlink:>{w_link}} {owner:<{w_owner}} "
            f"{group:<{w_group}} {size:>{w_size}} {mtime} {name}"
        )

    return "\n".join(lines)

