def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    parser = etree.XMLParser(
        resolve_entities=False,
        no_network=True,
        load_dtd=False,
    )
    try:
        root = etree.fromstring(xml_data, parser=parser)
    except etree.XMLSyntaxError:
        return None

    for student in root.findall("student"):
        user_el = student.find("username")
        pass_el = student.find("password")
        if user_el is None or pass_el is None:
            continue
        if (user_el.text or "") == username and (pass_el.text or "") == password:
            return {child.tag: child.text or "" for child in student}

    return None

