import struct


def _ssh_string(s):
    if isinstance(s, str):
        s = s.encode("utf-8")
    return struct.pack(">I", len(s)) + s


def _ssh_mpint(n):
    if n == 0:
        data = b""
    else:
        data = n.to_bytes((n.bit_length() + 7) // 8, "big")
        if data[0] & 0x80:
            data = b"\x00" + data
    return struct.pack(">I", len(data)) + data


def generate_private_key():
    key = DSA.generate(2048)
    blob = (
        _ssh_string("ssh-dss")
        + _ssh_mpint(key.p)
        + _ssh_mpint(key.q)
        + _ssh_mpint(key.g)
        + _ssh_mpint(key.y)
    )
    return "ssh-dss " + base64.b64encode(blob).decode("ascii")

