import hashlib
import hmac


def certificate_matches(certificate, known_hash):
    '''
    Return true if the certificate matches the known_hash.
    '''
    if isinstance(known_hash, str):
        known_hash = known_hash.encode('ascii')

    hasher = hashlib.sha256(certificate)
    raw_digest = hasher.digest()

    if len(known_hash) == len(raw_digest):
        return hmac.compare_digest(raw_digest, known_hash)

    hex_digest = hasher.hexdigest().encode('ascii')
    return hmac.compare_digest(hex_digest, known_hash.lower())

